import javax.swing.*;
import javax.swing.text.*;
import java.awt.*;

public class NumericTextField extends PlainDocument {
 private int maxLength;

 public NumericTextField(int maxLength) {
 this.maxLength = maxLength;
 }

 @Override
 public void insertString(int offset, String str, AttributeSet attr) 
 throws BadLocationException {
 if (str == null) return;

 // Check length limit
 String currentText = getText(0, getLength());
 if (currentText.length() + str.length() > maxLength) {
 return; // Reject insertion
 }

 // Check if all characters are digits
 StringBuilder filtered = new StringBuilder();
 for (char c : str.toCharArray()) {
 if (Character.isDigit(c)) {
 filtered.append(c);
 }
 }

 if (filtered.length() > 0) {
 super.insertString(offset, filtered.toString(), attr);
 }
 }
}

