import javax.swing.*;
import javax.swing.event.*;
import java.awt.*;
import java.awt.event.*;

public class LoginFormDemo extends JFrame {
 private JTextField usernameField;
 private JPasswordField passwordField;
 private JButton loginButton;
 private JLabel statusLabel;

 public LoginFormDemo() {
 setTitle("Login Form");
 setDefaultCloseOperation(JFrame.EXIT_ON_CLOSE);
 setLayout(new BorderLayout(10, 10));

 // Create panel with GridLayout
 JPanel formPanel = new JPanel(new GridLayout(3, 2, 5, 5));
 formPanel.setBorder(BorderFactory.createEmptyBorder(10, 10, 10, 10));

 // Username field
 formPanel.add(new JLabel("Username:"));
 usernameField = new JTextField(20);
 usernameField.setDocument(new NumericTextField(15)); // Max 15 chars
 formPanel.add(usernameField);

 // Password field
 formPanel.add(new JLabel("Password:"));
 passwordField = new JPasswordField(20);
 formPanel.add(passwordField);

 // Status label
 formPanel.add(new JLabel(""));
 statusLabel = new JLabel("Enter credentials");
 statusLabel.setForeground(Color.BLUE);
 formPanel.add(statusLabel);

 add(formPanel, BorderLayout.CENTER);

 // Add DocumentListener to username for real-time validation
 usernameField.getDocument().addDocumentListener(new DocumentListener() {
 public void insertUpdate(DocumentEvent e) {
 validateUsername();
 }
 public void removeUpdate(DocumentEvent e) {
 validateUsername();
 }
 public void changedUpdate(DocumentEvent e) {}

 private void validateUsername() {
 String text = usernameField.getText();
 if (text.matches("^[a-zA-Z0-9_]+$")) {
 statusLabel.setText("Valid username");
 statusLabel.setForeground(Color.GREEN);
 } else {
 statusLabel.setText("Use only letters, numbers, underscore");
 statusLabel.setForeground(Color.RED);
 }
 }
 });

 // Add ActionListener to password field for submission
 passwordField.addActionListener(e -> performLogin());

 // Add ActionListener to username field
 usernameField.addActionListener(e -> passwordField.requestFocusInWindow());

 pack();
 setLocationRelativeTo(null);
 }

 private void performLogin() {
 String username = usernameField.getText();
 String password = new String(passwordField.getPassword());

 // Simple validation (demo purposes)
 if (username.isEmpty() || password.isEmpty()) {
 statusLabel.setText("Please fill all fields");
 statusLabel.setForeground(Color.RED);
 return;
 }

 // Check credentials (demo)
 if (username.equals("admin") && password.equals("password123")) {
 statusLabel.setText("Login successful!");
 statusLabel.setForeground(Color.GREEN);
 } else {
 statusLabel.setText("Invalid credentials");
 statusLabel.setForeground(Color.RED);
 passwordField.setText(""); // Clear password
 passwordField.requestFocusInWindow();
 }

 // Clear password array for security
 Arrays.fill(password.toCharArray(), ' ');
 }

 public static void main(String[] args) {
 SwingUtilities.invokeLater(() -> {
 new LoginFormDemo().setVisible(true);
 });
 }
}

import javax.swing.*;
import javax.swing.text.*;
import java.awt.*;
import java.text.*;

public class CurrencyTextField extends JTextField {
 private DecimalFormat formatter;

 public CurrencyTextField() {
 super();
 // Format: $1,234.56
 formatter = new DecimalFormat("$#,##0.00");
 setDocument(new CurrencyDocument());
 setText("0.00");
 }

 public double getCurrencyValue() {
 try {
 String text = getText().replace("$", "").replace(",", "");
 return Double.parseDouble(text);
 } catch (NumberFormatException e) {
 return 0.0;
 }
 }

 private class CurrencyDocument extends PlainDocument {
 @Override
 public void insertString(int offset, String str, AttributeSet attr) 
 throws BadLocationException {
 if (str == null) return;

 // Remove any non-digit characters from input
 StringBuilder numericInput = new StringBuilder();
 for (char c : str.toCharArray()) {
 if (Character.isDigit(c) || c == '.') {
 numericInput.append(c);
 }
 }

 if (numericInput.length() == 0) return;

 // Get current text without formatting
 String currentText = getText(0, getLength())
 .replace("$", "").replace(",", "");

 // Insert new digits in correct position
 String newText = currentText.substring(0, offset) + 
 numericInput + currentText.substring(offset);

 try {
 // Parse as decimal (scale by 100 to handle cents properly)
 double value = Double.parseDouble(newText) / 100;
 String formatted = formatter.format(value);
 super.remove(0, getLength());
 super.insertString(0, formatted, attr);
 } catch (NumberFormatException e) {
 // Invalid input, ignore
 }
 }

 @Override
 public void remove(int offset, int length) throws BadLocationException {
 String currentText = getText(0, getLength())
 .replace("$", "").replace(",", "");

 if (offset >= currentText.length()) return;

 String newText = currentText.substring(0, offset) + 
 currentText.substring(offset + length);

 try {
 double value = newText.isEmpty() ? 0 : Double.parseDouble(newText) / 100;
 String formatted = formatter.format(value);
 super.remove(0, getLength());
 if (!formatted.equals("$0.00") || newText.isEmpty()) {
 super.insertString(0, formatted, null);
 }
 } catch (NumberFormatException e) {
 super.remove(offset, length);
 }
 }
 }

 public static void main(String[] args) {
 SwingUtilities.invokeLater(() -> {
 JFrame frame = new JFrame("Currency Input Demo");
 frame.setDefaultCloseOperation(JFrame.EXIT_ON_CLOSE);
 frame.setLayout(new FlowLayout());

 frame.add(new JLabel("Enter Amount:"));
 CurrencyTextField currencyField = new CurrencyTextField();
 currencyField.setColumns(15);
 frame.add(currencyField);

 JButton getValueBtn = new JButton("Get Value");
 getValueBtn.addActionListener(e -> {
 JOptionPane.showMessageDialog(frame, 
 "Value: " + currencyField.getCurrencyValue());
 });
 frame.add(getValueBtn);

 frame.pack();
 frame.setLocationRelativeTo(null);
 frame.setVisible(true);
 });
 }
}
